@namespace Lumeo

<div class="relative w-full overflow-auto">
    <table class="@CssClass" @attributes="AdditionalAttributes">
        @ChildContent
    </table>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"w-full caption-bottom text-sm {Class}".Trim();
}

@namespace Lumeo

<tbody class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</tbody>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"[&_tr:last-child]:border-0 {Class}".Trim();
}

